var parts = msg.topic.split('/');
var deviceId = parts[1] || 'unknown';
var metric = '';
var value = 0;
for (var key in msg.payload) {
    if (typeof msg.payload[key] === 'number') {
        metric = key;
        value = msg.payload[key];
        break;
    }
    if (typeof msg.payload[key] === 'object') {
        for (var subkey in msg.payload[key]) {
            if (typeof msg.payload[key][subkey] === 'number') {
                metric = subkey;
                value = msg.payload[key][subkey];
                break;
            }
        }
        if (metric) break;
    }
}
var latest = flow.get('latest') || {};
latest[deviceId] = {
    device_id: deviceId,
    metric: metric,
    value: value,
    timestamp: Date.now(),
    source_proto: 'mqtt'
};
flow.set('latest', latest);
var count = flow.get('msg_count') || 0;
flow.set('msg_count', count + 1);
return msg;

var deviceId = msg.req.params.deviceId;
var latest = flow.get('latest') || {};
var data = latest[deviceId];
if (!data) {
    msg.statusCode = 404;
    msg.payload = { error: 'no data for device' };
} else {
    msg.payload = data;
}
return msg;

var latest = flow.get('latest') || {};
var deviceCount = Object.keys(latest).length;
var msgCount = flow.get('msg_count') || 0;
var startTime = flow.get('start_time') || Date.now();
var uptimeSec = Math.floor((Date.now() - startTime) / 1000);
msg.payload = {
    uptime_seconds: uptimeSec,
    device_count: deviceCount,
    messages_processed: msgCount,
    runtime: 'Node-RED'
};
return msg;

flow.set('start_time', Date.now());
flow.set('msg_count', 0);
flow.set('latest', {});
return msg;

var deviceId = msg.req.params.deviceId;
var latest = flow.get('latest') || {};
latest[deviceId] = {
    device_id: deviceId,
    metric: msg.payload.metric || '',
    value: msg.payload.value || 0,
    unit: msg.payload.unit || '',
    timestamp: Date.now(),
    source_proto: 'http'
};
flow.set('latest', latest);
var count = flow.get('msg_count') || 0;
flow.set('msg_count', count + 1);
msg.payload = { message_id: Date.now().toString(16), status: 'accepted' };
msg.statusCode = 202;
return msg;
